sql:
SELECT user_id, COUNT(*) AS total_rides
FROM bike_rides
GROUP BY user_id;

SELECT date, total_rides, average_duration_minutes, total_distance_km, most_popular_station_id, average_speed_kmh, total_revenue
FROM daily_rides
WHERE date = '2023-05-01';

SELECT ride_id, duration_minutes
FROM bike_rides
WHERE duration_minutes > (SELECT AVG(duration_minutes) FROM bike_rides);

SELECT total_rides
   FROM daily_rides
   ORDER BY date;

SELECT SUM(total_revenue) AS total_revenue_day
FROM daily_rides
WHERE date = '2023-09-15';

SELECT date, total_rides
FROM daily_rides
ORDER BY total_rides DESC;

SELECT COUNT(*) AS total_rides
FROM bike_rides
WHERE DATE(start_time) = '2023-04-01';
